;(()=>{try{
  const isAdmin=/^\/admin\/properties\/(add|edit\/\d+)/.test(location.pathname);
  if(!isAdmin) return;
  let videoVal="";
  const ensureInput=()=>{
    if(document.getElementById("videoUrlInput")) return;
    const labels=[...document.querySelectorAll("label")];
    const propertyImagesLabel=labels.find(l=>/property images/i.test(l.textContent||""));
    const featuredLabel=labels.find(l=>/featured property/i.test(l.textContent||""));
    const mount=(propertyImagesLabel&&propertyImagesLabel.parentElement)||(featuredLabel&&featuredLabel.parentElement)||document.querySelector("form");
    const wrap=document.createElement("div");
    wrap.className="space-y-2";
    wrap.innerHTML=`<label class="block text-sm font-medium mb-1">Video URL</label>
      <input id="videoUrlInput" type="url" placeholder="Paste YouTube or Telegram link" class="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm" /> 
      <p class="text-xs text-muted-foreground">Optional: YouTube link will embed. Telegram link will open in a new tab.</p>`;
    // insert after Property Images block, fallback to after Featured Property
    const imageContainer=(propertyImagesLabel&&((propertyImagesLabel.closest("div")&&propertyImagesLabel.closest("div").parentElement)||propertyImagesLabel.parentElement))||null;
    const featuredContainer=(featuredLabel&&((featuredLabel.closest("div")&&featuredLabel.closest("div").parentElement)||featuredLabel.parentElement))||null;
    if(imageContainer && imageContainer.parentElement){
      imageContainer.insertAdjacentElement("afterend", wrap);
    } else if(featuredContainer && featuredContainer.parentElement){
      featuredContainer.insertAdjacentElement("afterend", wrap);
    } else if(mount){
      mount.appendChild(wrap);
    }
    const inp=wrap.querySelector("#videoUrlInput");
    inp.addEventListener("input",()=>{videoVal=inp.value||"";});
  };
  const ready=()=>{
    ensureInput();
    const origFetch=window.fetch;
    if(window.__videoFetchPatched) return;
    window.__videoFetchPatched=true;
    window.fetch=async (input, init={})=>{
      try{
        const url=typeof input==="string"?input:(input&&input.url)||"";
        const method=((init&&init.method)||"GET").toUpperCase();
        // capture GET property to prefill input
        if(method==="GET" && /\/api\/admin\/properties\/\d+/.test(url)){
          const res=await origFetch(input, init);
          try{
            const clone=res.clone();
            clone.json().then(data=>{
              const v=(data&& (data.videoUrl||data.video_url)) || "";
              const inp=document.getElementById("videoUrlInput");
              if(inp && v && !inp.value){ inp.value=v; videoVal=v; }
            }).catch(()=>{});
          }catch(e){}
          return res;
        }
        if((method==="POST"||method==="PATCH"||method==="PUT") && /\/api\/admin\/properties(\/\d+)?/.test(url) && init && typeof init.body==="string" && init.headers){
          let bodyObj=null;
          try{ bodyObj=JSON.parse(init.body); }catch(e){}
          if(bodyObj && typeof bodyObj==="object"){
            if(bodyObj.bedrooms===undefined||bodyObj.bedrooms===null||bodyObj.bedrooms==="") bodyObj.bedrooms=0;
            if(bodyObj.bathrooms===undefined||bodyObj.bathrooms===null||bodyObj.bathrooms==="") bodyObj.bathrooms=0;
            // keep 0 as 0
            if(videoVal) bodyObj.videoUrl=videoVal;
            // also support if input already in DOM
            const inp=document.getElementById("videoUrlInput");
            if(inp && inp.value) bodyObj.videoUrl=inp.value;
            init={...init, body: JSON.stringify(bodyObj)};
          }
        }
      }catch(e){}
      return origFetch(input, init);
    };
  };
  if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",ready);} else {ready();}
  // keep trying in case React rerenders
  setInterval(ensureInput,1500);
}catch(e){}})();


;(function(){
  try{
    function isHome(){
      var p = (location && location.pathname) ? location.pathname : "/";
      return p === "/" || p === "" || /^\/\?/.test(p);
    }
    if(!isHome()) return;

    function textOf(el){
      try { return (el && (el.innerText || el.textContent) || "").trim(); } catch(e){ return ""; }
    }

    function findContactCard(){
      // Find container that has two "Chat on WhatsApp" buttons (duplicate issue)
      var nodes = Array.from(document.querySelectorAll("a,button"));
      var wa = nodes.filter(function(n){
        var t = textOf(n);
        return /chat on whatsapp/i.test(t);
      });
      if(wa.length < 2) return null;

      // choose the closest common ancestor for the first two matches
      function ancestors(el){
        var arr=[];
        while(el && el.parentElement){
          el=el.parentElement;
          arr.push(el);
          if(arr.length>25) break;
        }
        return arr;
      }
      var a1=ancestors(wa[0]), a2=ancestors(wa[1]);
      for(var i=0;i<a1.length;i++){
        if(a2.indexOf(a1[i])!==-1){
          return a1[i];
        }
      }
      return wa[0].closest("section,div") || null;
    }

    function apply(){
      var card = findContactCard();
      if(!card) return;

      // Remove duplicate WhatsApp buttons (keep the first)
      var waBtns = Array.from(card.querySelectorAll("a,button")).filter(function(n){
        return /chat on whatsapp/i.test(textOf(n));
      });
      for(var i=1;i<waBtns.length;i++){
        if(waBtns[i] && waBtns[i].parentElement){
          waBtns[i].parentElement.removeChild(waBtns[i]);
        }
      }

      // Remove "Call Us Now" duplicate link/button if present
      var callBtns = Array.from(card.querySelectorAll("a,button")).filter(function(n){
        return /call us now/i.test(textOf(n));
      });
      callBtns.forEach(function(n){
        if(n && n.parentElement){
          n.parentElement.removeChild(n);
        }
      });

      // Replace the left text block with a background image panel
      var candidates = Array.from(card.querySelectorAll("div,p")).filter(function(n){
        var t = textOf(n);
        return /visit our office/i.test(t) || /contact our property team directly/i.test(t);
      });

      var target = candidates.length ? candidates[0].closest("div") : null;
      if(!target){
        // fallback: first column inside the card
        var cols = Array.from(card.children).filter(function(c){ return c && c.nodeType===1; });
        target = cols.length ? cols[0] : card;
      }

      // Clean target content and apply bg
      if(target){
        target.innerHTML = "";
        target.style.minHeight = "220px";
        target.style.borderRadius = "16px";
        target.style.backgroundImage = 'url("/addis-bg.jpg"), url("/assets/addis-bg.jpg")';
        target.style.backgroundSize = "cover";
        target.style.backgroundPosition = "center";
        target.style.backgroundRepeat = "no-repeat";
        target.style.display = "flex";
        target.style.alignItems = "flex-end";
        target.style.justifyContent = "flex-start";
        target.style.padding = "16px";

        // Optional overlay for readability
        var overlay = document.createElement("div");
        overlay.style.width = "100%";
        overlay.style.borderRadius = "12px";
        overlay.style.padding = "10px 12px";
        overlay.style.background = "rgba(0,0,0,0.35)";
        overlay.style.color = "#fff";
        overlay.style.fontSize = "14px";
        overlay.style.lineHeight = "1.3";
        overlay.textContent = "Ethio Property - Addis Ababa";
        target.appendChild(overlay);
      }
    }

    apply();
    // keep trying in case React rerenders
    setInterval(apply, 2000);
  }catch(e){}
})();
